// Helper functions
export function getHistoricalDataByYear(year: number): HistoricalDebtData[] {
  return historicalDebtData.filter((item): item is HistoricalDebtData =>
    item !== undefined && item.year === year
  );
}

export function getHistoricalDataByProvince(province: string): HistoricalDebtData[] {
  return historicalDebtData.filter((item): item is HistoricalDebtData =>
    item !== undefined && item.province === province
  );
}

export function getAvailableYears(): number[] {
  return Array.from(new Set(historicalDebtData
    .filter((item): item is HistoricalDebtData => item !== undefined)
    .map(item => item.year))).sort();
}

export function getAvailableProvinces(): string[] {
  return Array.from(new Set(historicalDebtData
    .filter((item): item is HistoricalDebtData => item !== undefined)
    .map(item => item.province))).sort();
}
